import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { createUser, getUser, updateUser } from '../api';

export default function CreateMyCard() {
  const { id } = useParams();
  const navigate = useNavigate();

  const [form, setForm] = useState({
    name: '', jobTitle: '', department: '', companyName: '', email: '', phone: '', companyUrl: '', address: ''
  });
  const [socialJson, setSocialJson] = useState('[]');
  const [files, setFiles] = useState({ companyLogo: null, profilePicture: null, coverPhoto: null });
  const [preview, setPreview] = useState(null);
  const [loading, setLoading] = useState(false);
  const [qrUrl, setQrUrl] = useState(null);

  useEffect(() => {
    if (!id) return;
    setLoading(true);
    getUser(id)
      .then(u => {
        if (!u) return;
        setForm({
          name: u.name || '', jobTitle: u.jobTitle || '', department: u.department || '', companyName: u.companyName || '',
          email: u.email || '', phone: u.phone || '', companyUrl: u.companyUrl || '', address: u.address || ''
        });
        setPreview(u);
        if (u.socialLinks && Array.isArray(u.socialLinks)) setSocialJson(JSON.stringify(u.socialLinks, null, 2));
      })
      .catch(err => console.error('load failed', err))
      .finally(() => setLoading(false));
  }, [id]);

  // no scanner cleanup required for QR image

  function onChange(e){
    const { name, value } = e.target;
    setForm(f => ({ ...f, [name]: value }));
  }

  function onFileChange(e){
    const { name, files: f } = e.target;
    setFiles(prev => ({ ...prev, [name]: f && f[0] }));
  }

  async function onSave(e){
    e.preventDefault();
    setLoading(true);
    try{
      let socialStr = '';
      if (socialJson && socialJson.trim()){
        const parsed = JSON.parse(socialJson);
        if (!Array.isArray(parsed)) throw new Error('socialLinks must be a JSON array');
        socialStr = JSON.stringify(parsed);
      }

      const fd = new FormData();
      // Append only non-empty scalar fields so we don't send empty strings
      Object.entries(form).forEach(([k, v]) => {
        if (v !== null && v !== undefined && String(v).trim() !== '') {
          fd.append(k, v);
        }
      });

      // Append files only when the user selected them
      if (files.companyLogo) fd.append('companyLogo', files.companyLogo);
      if (files.profilePicture) fd.append('profilePicture', files.profilePicture);
      if (files.coverPhoto) fd.append('coverPhoto', files.coverPhoto);

      // Append social links only when present and valid
      if (socialStr) fd.append('socialLinks', socialStr);

      const saved = id ? await updateUser(id, fd) : await createUser(fd);
      setPreview(saved);
      if (saved && saved.id) navigate(`/create-my-card/${saved.id}`, { replace: true });
    }catch(err){
      console.error('save failed', err);
      const msg = err?.response?.data || err?.message || 'Unknown error';
      alert('Save failed: ' + msg);
    }finally{ setLoading(false); }
  }

  // QR rendering: create an image URL that encodes the absolute user URL
  useEffect(() => {
    const userId = id || (preview && preview.id);
    if (!userId) { setQrUrl(null); return; }
    const target = `${window.location.origin}/create-my-card/${userId}`;
    // Use a public QR image API to avoid adding a dependency
    const qr = `https://api.qrserver.com/v1/create-qr-code/?size=300x300&data=${encodeURIComponent(target)}`;
    setQrUrl(qr);
  }, [id, preview]);

  return (
    <div className="create-card" style={{ display: 'flex', gap: 24, padding: 24 }}>
      <div className="form-panel" style={{ flex: 1 }}>
        <h2>Create My Card</h2>
        <form onSubmit={onSave}>
          <div style={{ display: 'grid', gap: 8 }}>
            <label>Name<input name="name" value={form.name} onChange={onChange} /></label>
            <label>Job title<input name="jobTitle" value={form.jobTitle} onChange={onChange} /></label>
            <label>Department<input name="department" value={form.department} onChange={onChange} /></label>
            <label>Company<input name="companyName" value={form.companyName} onChange={onChange} /></label>
            <label>Email<input name="email" value={form.email} onChange={onChange} /></label>
            <label>Phone<input name="phone" value={form.phone} onChange={onChange} /></label>
            <label>Company URL<input name="companyUrl" value={form.companyUrl} onChange={onChange} /></label>
            <label>Address<input name="address" value={form.address} onChange={onChange} /></label>

            <label>Social links (JSON array)
              <textarea rows={6} value={socialJson} onChange={e => setSocialJson(e.target.value)} />
            </label>

            <label>Company Logo<input type="file" name="companyLogo" onChange={onFileChange} accept="image/*" /></label>
            <label>Profile Picture<input type="file" name="profilePicture" onChange={onFileChange} accept="image/*" /></label>
            <label>Cover Photo<input type="file" name="coverPhoto" onChange={onFileChange} accept="image/*" /></label>

            <div style={{ marginTop: 12 }}>
              <button type="submit" style={{ padding: '8px 16px' }} disabled={loading}>{id ? 'Update' : 'Save'}</button>
            </div>
          </div>
        </form>
      </div>

      <div className="preview-panel" style={{ width: 380 }}>
        <h3>Preview / Saved</h3>
        { (id || (preview && preview.id)) && (
          <div style={{ marginBottom: 12, textAlign: 'center' }}>
            <h4 style={{ margin: '6px 0' }}>Karekod (telefonla okutun)</h4>
            {qrUrl ? (
              <div style={{ display: 'flex', justifyContent: 'center' }}>
                <img src={qrUrl} alt={`QR for ${id || (preview && preview.id)}`} style={{ width: 220, height: 220, borderRadius: 8, background: '#fff', padding: 8 }} />
              </div>
            ) : (
              <div style={{ color: '#666' }}>Karekod oluşturuluyor…</div>
            )}
            <div style={{ marginTop: 8, fontSize: 13, color: '#444' }}>Telefonunuzun kamerasını karekoda tutun; sayfa açılacaktır.</div>
          </div>
        )}
        {loading && <div>Loading…</div>}
        {preview ? (
          <div className="card-preview">
            {/* Cover area with overlapping avatars */}
            <div style={{ position: 'relative', borderRadius: 6, overflow: 'hidden' }}>
              {preview.coverPhoto ? (
                <img src={preview.coverPhoto} alt="cover" style={{ width: '100%', height: 140, objectFit: 'cover', display: 'block' }} />
              ) : (
                <div style={{ width: '100%', height: 140, background: '#eee' }} />
              )}

              {/* left avatar (profile) */}
              {preview.profilePicture && (
                <img src={preview.profilePicture} alt="profile" style={{ position: 'absolute', left: 12, top: 34, width: 72, height: 72, objectFit: 'cover', borderRadius: 8, border: '3px solid #fff', boxShadow: '0 2px 6px rgba(0,0,0,0.15)' }} />
              )}

              {/* right avatar (company logo) */}
              {preview.companyLogo && (
                <img src={preview.companyLogo} alt="company logo" style={{ position: 'absolute', right: 12, top: 34, width: 72, height: 72, objectFit: 'cover', borderRadius: 8, border: '3px solid #fff', boxShadow: '0 2px 6px rgba(0,0,0,0.15)' }} />
              )}
            </div>

            {/* Text block below; add top margin so it doesn't collide with avatars */}
            <div style={{ marginTop: 18 }}>
              <h4 style={{ margin: 0 }}>{preview.name}</h4>
              <div style={{ color: '#555' }}>{preview.jobTitle}</div>
              <div style={{ color: '#777', fontSize: 13 }}>{preview.companyName}</div>
            </div>
            <div className="meta" style={{ marginTop: 8, color: '#333' }}>
              <div>{preview.email}</div>
              <div>{preview.phone}</div>
              <div>{preview.companyUrl}</div>
            </div>
            {preview.socialLinks && preview.socialLinks.length > 0 && (
              <div className="social-links" style={{ marginTop: 10 }}>
                <h5 style={{ margin: '8px 0' }}>Social</h5>
                <ul>
                  {preview.socialLinks.map((s, i) => (
                    <li key={i}>{s.platform}: {s.link}</li>
                  ))}
                </ul>
              </div>
            )}
          </div>
        ) : (
          <div>No saved data yet. Fill the form and hit Save.</div>
        )}
      </div>
    </div>
  );
}
